                    .run();

            try (Tensor<?> outputTensor = outputTensors.get(0)) {  // 使用 try-with-resources 自动关闭
                long outputSize = outputTensor.shape()[1];
                FloatBuffer floatBuffer = FloatBuffer.allocate((int) outputSize * x.length);
                outputTensor.writeTo(floatBuffer);
                floatBuffer.flip();  // 重置buffer的position

                // 使用 Java 8 Stream API 转换 buffer 到 double 数组
                return IntStream.range(0, floatBuffer.limit())
                        .mapToDouble(i -> (double) floatBuffer.get(i))
                        .toArray();
            }
        }
    } catch (Exception e) {
        e.printStackTrace();
        // 根据你的程序需求，你可以这里返回一个适当的值或者抛出异常
    }
    return new double[0];
}
```

