public class ModelPrediction {

    public double[] predict(double[][][] input, String modelDir) {
        double[] outputPredictions;

        // 加载模型
        try (SavedModelBundle bundle = SavedModelBundle.load(modelDir, "serve")) {
            try (Session session = bundle.session()) {
                // 创建输入Tensor
                TFloat32 inputTensor = TFloat32.tensorOf(TFloat32.DTYPE, Shape.of(input.length, 5, 40), DataBuffers.of(input));

                // 运行模型计算预测结果
                List<Tensor<?>> outputs = session.runner()
                    .feed("serving_default_input_1", inputTensor)
                    .fetch("StatefulPartitionedCall")
                    .run();

                // 获取并处理模型的输出
                try (Tensor<TFloat32> outputTensor = (Tensor<TFloat32>) outputs.get(0)) {
                    // 获取输出张量的值
                    outputPredictions = outputTensor.copyTo(new float[input.length][1])[0];
                }
            }
        }

        return outputPredictions;
    }
}
```

